(3, 'Mimisan', 'Penanganan untuk kondisi pendarahan dari hidung (epistaksis).', 1),
(4, 'Tersedak', 'Penanganan penyumbatan saluran pernapasan akibat benda asing pada dewasa maupun anak-anak.', 1),
(5, 'Pingsan', 'Penanganan untuk kehilangan kesadaran sementara akibat penurunan aliran darah ke otak.', 2),
(6, 'Keracunan', 'Langkah pertolongan pertama pada kondisi keracunan makanan, gas berbahaya, atau zat kimia.', 2),
(7, 'Gigitan Hewan', 'Penanganan terhadap gigitan serangga, ular, anjing, atau hewan liar lainnya.', 2),
(8, 'Sesak Napas', 'Pertolongan pertama untuk serangan asma atau kesulitan bernapas.', 2),
(9, 'Patah Tulang', 'Penanganan imobilisasi patah tulang atau retak sebelum ditangani medis.', 1),
(10, 'Serangan Jantung', 'Langkah darurat (CPR/RJP) untuk serangan jantung mendadak sebelum tim medis tiba.', 1);
