INSERT INTO `guides` (`id`, `judul`, `kategori_id`, `gejala`, `langkah_penanganan`, `gambar`, `user_id`) VALUES
(1, 'Pertolongan Pertama Luka Lecet dan Sayat', 1, 'Kulit tergores, pendarahan ringan hingga sedang, rasa perih pada permukaan kulit.', '1. Cuci tangan dengan sabun sebelum menangani luka.\r\n2. Bersihkan luka dengan air mengalir untuk membuang kotoran.\r\n3. Tekan luka lembut menggunakan kain bersih/kasa jika terjadi pendarahan ringan.\r\n4. Oleskan cairan antiseptik atau salep antibiotik jika diperlukan.\r\n5. Tutup luka dengan plester atau kasa steril untuk melindunginya dari kuman.\r\n6. Ganti balutan plester/kasa secara teratur.', NULL, 1),
(2, 'Penanganan Luka Bakar Ringan (Derajat 1 & 2)', 2, 'Kulit kemerahan, bengkak ringan, terasa panas/perih, muncul gelembung berair (blister).', '1. Siram luka bakar dengan air mengalir (suhu ruang) selama minimal 10-20 menit. Jangan gunakan air es atau es batu.\r\n2. Lepaskan perhiasan atau pakaian ketat di sekitar luka sebelum area bengkak.\r\n3. Jangan memecahkan gelembung berair (blister) karena rentan infeksi.\r\n4. Oleskan gel lidah buaya murni atau pelembap khusus luka bakar jika kulit tidak terbuka.\r\n5. Tutup longgar dengan kasa steril untuk melindungi dari gesekan.\r\n6. Minum obat pereda nyeri (seperti parasetamol) bila dirasa perlu.', NULL, 1),
(3, 'Mengatasi Mimisan (Pendarahan Hidung)', 3, 'Darah mengalir dari salah satu atau kedua lubang hidung, biasanya disertai sensasi hangat di hidung.', '1. Duduk tegak dan posisikan tubuh sedikit condong ke depan (jangan menengadah ke belakang agar darah tidak masuk tenggorokan).\r\n2. Jepit cuping hidung (bagian lunak) menggunakan ibu jari dan telunjuk.\r\n3. Bernapaslah melalui mulut selama menjepit hidung.\r\n4. Tahan jepitan selama 10-15 menit tanpa dilepas-lepas.\r\n5. Berikan kompres dingin pada pangkal hidung untuk mempersempit pembuluh darah.\r\n6. Jika pendarahan berlanjut lebih dari 20 menit, segera cari bantuan medis.', NULL, 1),
(4, 'Pertolongan Pertama Orang Tersedak (Metode Heimlich Maneuver)', 4, 'Sulit bernapas, tidak bisa berbicara/bersuara, memegang leher dengan kedua tangan, wajah membiru.', '1. Tanyakan: \"Apakah Anda tersedak?\" jika korban sadar dan bisa mengangguk.\r\n2. Berdirilah di belakang korban, lingkarkan lengan Anda di pinggang mereka.\r\n3. Kepalkan salah satu tangan Anda, letakkan di atas pusar korban (di bawah tulang dada).\r\n4. Genggam kepalan tangan tersebut dengan tangan satunya.\r\n5. Lakukan sentakan cepat ke arah atas dan dalam secara berulang (maksimal 5 kali).\r\n6. Jika korban pingsan, baringkan secara terlentang dan lakukan RJP/CPR sambil memanggil bantuan medis.', NULL, 1),
(5, 'Mengatasi Orang Pingsan (Hilang Kesadaran)', 5, 'Wajah pucat, keringat dingin, pusing sebelum pingsan, tubuh limbung dan jatuh tidak sadarkan diri.', '1. Pindahkan korban ke tempat yang aman, teduh, dan memiliki sirkulasi udara baik.\r\n2. Baringkan korban secara terlentang secara mendatar.\r\n3. Tinggikan posisi kaki korban sekitar 30 cm di atas level jantung (menggunakan bantal/tas) untuk mengalirkan darah kembali ke otak.\r\n4. Longgarkan pakaian ketat korban (kancing kerah, ikat pinggang, bra).\r\n5. Cek pernapasan korban. Jika bernapas, tunggu 1-2 menit hingga sadar.\r\n6. Jika sadar, biarkan berbaring sejenak dan jangan terburu-buru dibangunkan. Berikan minum air putih hangat setelah benar-benar sadar.', NULL, 2),
(6, 'Penanganan Pertama Keracunan Makanan', 6, 'Mual, muntah-muntah, diare, sakit perut melilit, pusing, lemas setelah mengonsumsi makanan/minuman tertentu.', '1. Pastikan korban minum air putih hangat dalam jumlah cukup untuk mencegah dehidrasi.\r\n2. Berikan tablet karbon aktif (norit) sesuai dosis jika ada, untuk menyerap racun di lambung.\r\n3. Jangan memaksakan diri untuk muntah kecuali disarankan oleh petugas medis.\r\n4. Hindari memberikan susu, kopi, atau obat anti-diare terlebih dahulu.\r\n5. Istirahatkan tubuh secara total.\r\n6. Bawa ke puskesmas/rumah sakit terdekat apabila gejala muntah hebat atau disertai sesak napas.', NULL, 2),
(7, 'Mengatasi Gigitan Ular (Pertolongan Awal)', 7, 'Bekas taring gigitan, nyeri hebat, bengkak, memar di sekitar luka, pusing, keringat dingin.', '1. Tetap tenang dan jangan biarkan korban banyak bergerak (imobilisasi total area gigitan untuk memperlambat penyebaran racun).\r\n2. Posisikan area gigitan lebih rendah dari posisi jantung.\r\n3. Bersihkan luka gigitan dengan air mengalir secara perlahan (jangan digosok keras).\r\n4. Jangan menghisap racun dengan mulut, jangan mengikat kencang (torniket), dan jangan memotong luka.\r\n5. Longgarkan pakaian atau perhiasan di sekitar area gigitan.\r\n6. Pasang bidai longgar untuk menjaga sendi di sekitar luka tidak bergerak, lalu segera bawa ke rumah sakit untuk mendapatkan serum anti-bisa ular (SABU).', NULL, 2),
(8, 'Mengatasi Serangan Asma (Sesak Napas)', 8, 'Suara napas berbunyi (mengi/wheezing), napas memburu dan dangkal, batuk-batuk, sulit berbicara.', '1. Bantu korban untuk duduk tegak dalam posisi nyaman (jangan biarkan berbaring).\r\n2. Bantu korban mengambil dan menggunakan obat inhaler mereka (jika membawa).\r\n3. Longgarkan pakaian korban yang ketat.\r\n4. Minta korban menarik napas dalam secara perlahan melalui hidung dan mengeluarkannya lewat mulut untuk menenangkan diri.\r\n5. Jauhkan korban dari pemicu asma (seperti debu, dingin, asap rorok, atau hewan peliharaan).\r\n6. Hubungi nomor darurat medis apabila serangan tidak membaik setelah menggunakan inhaler.', NULL, 2),
(9, 'Pertolongan Pertama Patah Tulang (Fraktur)', 9, 'Nyeri hebat, bengkak, memar, bentuk sendi/tulang tidak normal (deformitas), kesulitan menggerakkan anggota tubuh.', '1. Jangan mencoba meluruskan atau mengembalikan posisi tulang yang patah.\r\n2. Jika ada pendarahan pada patah tulang terbuka, tekan lembut sekitar luka dengan kasa bersih untuk mengontrol darah.\r\n3. Lakukan imobilisasi dengan memasang bidai (papan/karton tebal) yang disangga kain mitela pada sendi di atas dan di bawah patah tulang.\r\n4. Usahakan bagian yang patah tidak bergerak sama sekali selama menunggu bantuan medis.\r\n5. Berikan kompres es dibungkus handuk pada area bengkak (jangan tempelkan es langsung ke luka terbuka).\r\n6. Segera panggil ambulans atau bawa korban ke rumah sakit.', NULL, 1),
(10, 'Penanganan Darurat Serangan Jantung', 10, 'Nyeri dada kiri seperti ditekan atau diremas yang menjalar ke lengan kiri, leher, atau punggung; sesak napas; keringat dingin.', '1. Segera hubungi nomor darurat 119 atau 112 untuk meminta ambulans.\r\n2. Posisikan korban duduk bersandar setengah berbaring (sudut 45 derajat) agar jantung tidak bekerja terlalu keras.\r\n3. Longgarkan pakaian ketat mereka.\r\n4. Jika korban sadar dan memiliki obat jantung pribadi (seperti ISDN/Nitrogliserin), bantu mereka meletakkannya di bawah lidah.\r\n5. Jika korban kehilangan kesadaran dan berhenti bernapas, segera lakukan tindakan RJP/CPR (Resusitasi Jantung Paru) dengan kompresi dada sedalam 5-6 cm di tengah dada sebanyak 100-120 kali per menit.\r\n6. Lakukan CPR terus-menerus hingga bantuan medis tiba atau korban menunjukkan tanda kehidupan.', NULL, 1);
